    17→package version
    18→
    19→import (
    20→	"fmt"
    21→	"runtime"
    22→	"sync/atomic"
    23→
    24→	"k8s.io/apimachinery/pkg/util/version"
    25→	apimachineryversion "k8s.io/apimachinery/pkg/version"
    26→)
    27→
    28→type EffectiveVersion interface {
    29→	BinaryVersion() *version.Version
    30→	EmulationVersion() *version.Version
    31→	MinCompatibilityVersion() *version.Version
    32→	EqualTo(other EffectiveVersion) bool
    33→	String() string
    34→	Validate() []error
    35→}
    36→
    37→type MutableEffectiveVersion interface {
    38→	EffectiveVersion
    39→	Set(binaryVersion, emulationVersion, minCompatibilityVersion *version.Version)
    40→	SetEmulationVersion(emulationVersion *version.Version)
    41→	SetMinCompatibilityVersion(minCompatibilityVersion *version.Version)
    42→}
    43→
    44→type effectiveVersion struct {
    45→	// When true, BinaryVersion() returns the current binary version
    46→	useDefaultBuildBinaryVersion atomic.Bool
    47→	// Holds the last binary version stored in Set()
    48→	binaryVersion atomic.Pointer[version.Version]
    49→	// If the emulationVersion is set by the users, it could only contain major and minor versions.
    50→	// In tests, emulationVersion could be the same as the binary version, or set directly,
    51→	// which can have "alpha" as pre-release to continue serving expired apis while we clean up the test.
    52→	emulationVersion atomic.Pointer[version.Version]
    53→	// minCompatibilityVersion could only contain major and minor versions.
    54→	minCompatibilityVersion atomic.Pointer[version.Version]
    55→}
    56→
    57→// Get returns the overall codebase version. It's for detecting
    58→// what code a binary was built from.
    59→func Get() apimachineryversion.Info {
    60→	// These variables typically come from -ldflags settings and in
    61→	// their absence fallback to the settings in ./base.go
    62→	return apimachineryversion.Info{
    63→		Major:        gitMajor,
    64→		Minor:        gitMinor,
    65→		GitVersion:   dynamicGitVersion.Load().(string),
    66→		GitCommit:    gitCommit,
    67→		GitTreeState: gitTreeState,
    68→		BuildDate:    buildDate,
    69→		GoVersion:    runtime.Version(),
    70→		Compiler:     runtime.Compiler,
    71→		Platform:     fmt.Sprintf("%s/%s", runtime.GOOS, runtime.GOARCH),
    72→	}
    73→}
    74→
    75→func (m *effectiveVersion) BinaryVersion() *version.Version {
    76→	if m.useDefaultBuildBinaryVersion.Load() {
    77→		return defaultBuildBinaryVersion()
    78→	}
    79→	return m.binaryVersion.Load()
    80→}
    81→
    82→func (m *effectiveVersion) EmulationVersion() *version.Version {
    83→	ver := m.emulationVersion.Load()
    84→	if ver != nil {
    85→		// Emulation version can have "alpha" as pre-release to continue serving expired apis while we clean up the test.
    86→		// The pre-release should not be accessible to the users.
    87→		return ver.WithPreRelease(m.BinaryVersion().PreRelease())
    88→	}
    89→	return ver
    90→}
    91→
    92→func (m *effectiveVersion) MinCompatibilityVersion() *version.Version {
    93→	return m.minCompatibilityVersion.Load()
    94→}
    95→
    96→func (m *effectiveVersion) EqualTo(other EffectiveVersion) bool {
    97→	return m.BinaryVersion().EqualTo(other.BinaryVersion()) && m.EmulationVersion().EqualTo(other.EmulationVersion()) && m.MinCompatibilityVersion().EqualTo(other.MinCompatibilityVersion())
    98→}
    99→
   100→func (m *effectiveVersion) String() string {
   101→	if m == nil {
   102→		return "<nil>"
   103→	}
   104→	return fmt.Sprintf("{BinaryVersion: %s, EmulationVersion: %s, MinCompatibilityVersion: %s}",
   105→		m.BinaryVersion().String(), m.EmulationVersion().String(), m.MinCompatibilityVersion().String())
   106→}
   107→
   108→func majorMinor(ver *version.Version) *version.Version {
   109→	if ver == nil {
   110→		return ver
   111→	}
   112→	return version.MajorMinor(ver.Major(), ver.Minor())
   113→}
   114→
   115→func (m *effectiveVersion) Set(binaryVersion, emulationVersion, minCompatibilityVersion *version.Version) {
   116→	m.binaryVersion.Store(binaryVersion)
   117→	m.useDefaultBuildBinaryVersion.Store(false)
   118→	m.emulationVersion.Store(majorMinor(emulationVersion))
   119→	m.minCompatibilityVersion.Store(majorMinor(minCompatibilityVersion))
   120→}
   121→
   122→func (m *effectiveVersion) SetEmulationVersion(emulationVersion *version.Version) {
   123→	m.emulationVersion.Store(majorMinor(emulationVersion))
   124→}
   125→
   126→func (m *effectiveVersion) SetMinCompatibilityVersion(minCompatibilityVersion *version.Version) {
   127→	m.minCompatibilityVersion.Store(majorMinor(minCompatibilityVersion))
   128→}
   129→
   130→func (m *effectiveVersion) Validate() []error {
   131→	var errs []error
   132→	// Validate only checks the major and minor versions.
   133→	binaryVersion := m.BinaryVersion().WithPatch(0)
   134→	emulationVersion := m.emulationVersion.Load()
   135→	minCompatibilityVersion := m.minCompatibilityVersion.Load()
   136→
   137→	// emulationVersion can only be 1.{binaryMinor-1}...1.{binaryMinor}.
   138→	maxEmuVer := binaryVersion
   139→	minEmuVer := binaryVersion.SubtractMinor(1)
   140→	if emulationVersion.GreaterThan(maxEmuVer) || emulationVersion.LessThan(minEmuVer) {
   141→		errs = append(errs, fmt.Errorf("emulation version %s is not between [%s, %s]", emulationVersion.String(), minEmuVer.String(), maxEmuVer.String()))
   142→	}
   143→	// minCompatibilityVersion can only be 1.{binaryMinor-1} for alpha.
   144→	maxCompVer := binaryVersion.SubtractMinor(1)
   145→	minCompVer := binaryVersion.SubtractMinor(1)
   146→	if minCompatibilityVersion.GreaterThan(maxCompVer) || minCompatibilityVersion.LessThan(minCompVer) {
   147→		errs = append(errs, fmt.Errorf("minCompatibilityVersion version %s is not between [%s, %s]", minCompatibilityVersion.String(), minCompVer.String(), maxCompVer.String()))
   148→	}
   149→	return errs
   150→}
   151→
   152→func newEffectiveVersion(binaryVersion *version.Version, useDefaultBuildBinaryVersion bool) MutableEffectiveVersion {
   153→	effective := &effectiveVersion{}
   154→	compatVersion := binaryVersion.SubtractMinor(1)
   155→	effective.Set(binaryVersion, binaryVersion, compatVersion)
   156→	effective.useDefaultBuildBinaryVersion.Store(useDefaultBuildBinaryVersion)
   157→	return effective
   158→}
   159→
   160→func NewEffectiveVersion(binaryVer string) MutableEffectiveVersion {
   161→	if binaryVer == "" {
   162→		return &effectiveVersion{}
   163→	}
   164→	binaryVersion := version.MustParse(binaryVer)
   165→	return newEffectiveVersion(binaryVersion, false)
   166→}
   167→
   168→func defaultBuildBinaryVersion() *version.Version {
   169→	verInfo := Get()
   170→	return version.MustParse(verInfo.String()).WithInfo(verInfo)
   171→}
   172→
   173→// DefaultBuildEffectiveVersion returns the MutableEffectiveVersion based on the
   174→// current build information.
   175→func DefaultBuildEffectiveVersion() MutableEffectiveVersion {
   176→	binaryVersion := defaultBuildBinaryVersion()
   177→	if binaryVersion.Major() == 0 && binaryVersion.Minor() == 0 {
   178→		return DefaultKubeEffectiveVersion()
   179→	}
   180→	return newEffectiveVersion(binaryVersion, true)
   181→}
   182→
   183→// DefaultKubeEffectiveVersion returns the MutableEffectiveVersion based on the
   184→// latest K8s release.
   185→func DefaultKubeEffectiveVersion() MutableEffectiveVersion {
   186→	binaryVersion := version.MustParse(DefaultKubeBinaryVersion).WithInfo(Get())
   187→	return newEffectiveVersion(binaryVersion, false)
   188→}
   189→
   190→// ValidateKubeEffectiveVersion validates the EmulationVersion is equal to the binary version at 1.31 for kube components.
   191→// emulationVersion is introduced in 1.31, so it is only allowed to be equal to the binary version at 1.31.
   192→func ValidateKubeEffectiveVersion(effectiveVersion EffectiveVersion) error {
   193→	binaryVersion := version.MajorMinor(effectiveVersion.BinaryVersion().Major(), effectiveVersion.BinaryVersion().Minor())
   194→	if binaryVersion.EqualTo(version.MajorMinor(1, 31)) && !effectiveVersion.EmulationVersion().EqualTo(binaryVersion) {
   195→		return fmt.Errorf("emulation version needs to be equal to binary version(%s) in compatibility-version alpha, got %s",
   196→			binaryVersion.String(), effectiveVersion.EmulationVersion().String())
   197→	}
   198→	return nil
   199→}
